      '{\r\n  "extends": "@repo/typescript-config/nextjs.json",\r\n  "compilerOptions": {\r\n    "plugins": [\r\n      {\r\n        "name": "next"\r\n      }\r\n    ],\r\n    "paths": {\r\n      "@/*": ["./*"]\r\n    },\r\n    "allowJs": true,\r\n    "incremental": true\r\n  },\r\n  "include": ["next-env.d.ts", "**/*.ts", "**/*.tsx", ".next/types/**/*.ts"],\r\n  "exclude": ["node_modules"]\r\n}\r\n',
